import { useApp } from '../context/AppContext';

const LOGO = "data:image/png;base64,";

const menuItems = [
  { id: 'overview',    label: 'نظرة عامة', icon: '📊' },
  { id: 'restaurants', label: 'المطاعم',   icon: '🍽️' },
  { id: 'branches',    label: 'الفروع',    icon: '📍' },
  { id: 'offers',      label: 'العروض',    icon: '🎁' },
  { id: 'orders',      label: 'الطلبات',   icon: '🛍️' },
  { id: 'influencers', label: 'المؤثرين',  icon: '⭐' },
  { id: 'reports',     label: 'التقارير',  icon: '📈' },
  { id: 'settings',    label: 'الإعدادات', icon: '⚙️' },
];

export default function Sidebar() {
  const { currentPage, setCurrentPage, logout, adminUser } = useApp();

  return (
    <div style={{ width: '240px', background: 'white', height: '100vh', position: 'fixed', right: 0, top: 0, borderLeft: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', zIndex: 100 }}>

      <div style={{ padding: '20px 16px', borderBottom: '1px solid #e5e7eb', textAlign: 'center' }}>
        <img
          src={LOGO}
          alt="R2C Logo"
          style={{ width: '120px', height: '70px', objectFit: 'contain', marginBottom: '8px' }}
        />
        <div style={{ fontSize: '12px', color: '#ee7b26', marginTop: '4px' }}>● {adminUser?.email}</div>
      </div>

      <nav style={{ flex: 1, padding: '12px 8px', overflowY: 'auto' }}>
        {menuItems.map(item => (
          <div
            key={item.id}
            onClick={() => setCurrentPage(item.id)}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '12px',
              padding: '11px 16px',
              marginBottom: '2px',
              borderRadius: '10px',
              cursor: 'pointer',
              background: currentPage === item.id ? 'linear-gradient(135deg, #ee7b26, #ff9a4a)' : 'transparent',
              color: currentPage === item.id ? 'white' : '#4b5563',
              fontWeight: currentPage === item.id ? 'bold' : 'normal',
              fontSize: '15px',
            }}
          >
            <span style={{ fontSize: '18px' }}>{item.icon}</span>
            <span>{item.label}</span>
          </div>
        ))}
      </nav>

      <div style={{ padding: '16px' }}>
        <button
          onClick={logout}
          style={{
            width: '100%',
            padding: '11px',
            background: '#fff',
            color: '#dc2626',
            border: '1.5px solid #fca5a5',
            borderRadius: '10px',
            cursor: 'pointer',
            fontWeight: 'bold',
            fontSize: '15px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
          }}
        >
          🚪 تسجيل الخروج
        </button>
      </div>
    </div>
  );
}
